final:
module RefModule(
    A,
    B,
    SEL,
    Y
);// Module ports
    input  A;
    input  B;
    input  SEL;
    output Y;

    // Local signals
    wire unused_not_SEL;

    // Invert SEL signal
    not not_SEL_inst (
        unused_not_SEL,
        SEL
    );

    // Multiplexer
    assign Y = (SEL & A) | (unused_not_SEL & B);

endmodule
